import React, { useState, useEffect, useRef } from 'react';
import { User, Property, UserRole } from '../types';
import { Bell, Search, LogOut, Menu, Loader2, MapPin, X } from 'lucide-react';
import { supabase } from '../supabaseClient';

interface HeaderProps {
  user: User;
  onLogout: () => void;
  onOpenSidebar: () => void;
  onViewProperty: (id: string) => void;
}

const NOTIFICATION_SOUND = 'https://assets.mixkit.co/active_storage/sfx/2869/2869-preview.mp3';

const Header: React.FC<HeaderProps> = ({ user, onLogout, onOpenSidebar, onViewProperty }) => {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState<Property[]>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [showResults, setShowResults] = useState(false);
  const [unreadApplications, setUnreadApplications] = useState(0);
  const [showNotificationPopup, setShowNotificationPopup] = useState(false);
  const [showPropertyNotification, setShowPropertyNotification] = useState(false);
  const [lastAddedProperty, setLastAddedProperty] = useState<Property | null>(null);
  const searchRef = useRef<HTMLDivElement>(null);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  useEffect(() => {
    audioRef.current = new Audio(NOTIFICATION_SOUND);
    fetchInitialUnread();

    const channel = supabase
      .channel('header_notifications')
      .on('postgres_changes', { event: 'INSERT', table: 'job_applications' }, () => {
        setUnreadApplications(prev => prev + 1);
        setShowNotificationPopup(true);
        if (audioRef.current) audioRef.current.play().catch(() => {});
        setTimeout(() => setShowNotificationPopup(false), 5000);
      })
      .on('postgres_changes', { event: 'INSERT', table: 'properties' }, (payload) => {
        const adminRoles = [UserRole.ADMIN, UserRole.CEO, UserRole.MANAGER];
        if (adminRoles.includes(user.role)) {
          setLastAddedProperty(payload.new as Property);
          setShowPropertyNotification(true);
          if (audioRef.current) audioRef.current.play().catch(() => {});
          setTimeout(() => setShowPropertyNotification(false), 8000);
        }
      })
      .on('postgres_changes', { event: 'UPDATE', table: 'job_applications' }, () => {
        fetchInitialUnread();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, [user.role]);

  async function fetchInitialUnread() {
    const { count, error } = await supabase
      .from('job_applications')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'Pendente');

    if (!error) setUnreadApplications(count || 0);
  }

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (searchRef.current && !searchRef.current.contains(event.target as Node)) {
        setShowResults(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    const timer = setTimeout(async () => {
      if (query.trim().length < 2) {
        setResults([]);
        setIsSearching(false);
        return;
      }

      setIsSearching(true);
      try {
        const { data, error } = await supabase
          .from('properties')
          .select('*')
          .or(`title.ilike.%${query}%,location.ilike.%${query}%`)
          .limit(5);

        if (!error && data) {
          setResults(data);
        }
      } catch (err) {
        console.error("Search error:", err);
      } finally {
        setIsSearching(false);
        setShowResults(true);
      }
    }, 400);

    return () => clearTimeout(timer);
  }, [query]);

  const handleSelectResult = (id: string) => {
    onViewProperty(id);
    setQuery('');
    setShowResults(false);
  };

  return (
    <header className="h-14 border-b flex items-center justify-between px-4 md:px-6 shrink-0 relative z-[60] bg-white border-slate-200">
      <div className="flex items-center gap-3 flex-1">
        <button onClick={onOpenSidebar} className="md:hidden text-slate-500 p-1.5 hover:bg-slate-100 rounded-lg">
          <Menu size={20} />
        </button>

        <div ref={searchRef} className="hidden sm:flex relative max-w-xs w-full">
          <span className="absolute inset-y-0 left-3 flex items-center text-slate-400">
            {isSearching ? <Loader2 size={14} className="animate-spin text-blue-600" /> : <Search size={14} />}
          </span>
          <input
            type="text"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => query.length >= 2 && setShowResults(true)}
            placeholder="Pesquisar..."
            className="w-full pl-9 pr-8 py-1.5 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500/20 border transition-all text-xs font-medium bg-slate-50 border-slate-200 text-slate-900"
          />
          {query && (
            <button 
              onClick={() => {setQuery(''); setResults([]);}} 
              className="absolute inset-y-0 right-3 flex items-center text-slate-400 hover:text-slate-600"
            >
              <X size={14} />
            </button>
          )}

          {showResults && (query.length >= 2) && (
            <div className="absolute top-full left-0 right-0 mt-1 rounded-xl shadow-xl border overflow-hidden animate-in fade-in slide-in-from-top-1 duration-200 bg-white border-slate-100 shadow-slate-200/50">
              <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
                {results.length > 0 ? (
                  results.map((prop) => (
                    <button
                      key={prop.id}
                      onClick={() => handleSelectResult(prop.id)}
                      className="w-full flex items-center gap-3 p-3 transition-colors text-left border-b last:border-0 group hover:bg-slate-50 border-slate-50"
                    >
                      <img 
                        src={prop.image} 
                        alt="" 
                        className="w-8 h-8 rounded-md object-cover shadow-sm"
                      />
                      <div className="flex-1 min-w-0">
                        <p className="text-xs font-bold truncate text-slate-900">{prop.title}</p>
                        <p className="text-[10px] text-slate-500 truncate">{prop.location}</p>
                      </div>
                    </button>
                  ))
                ) : (
                  <div className="p-4 text-center text-slate-400 text-xs italic">Nenhum resultado</div>
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      <div className="flex items-center gap-3 md:gap-4">
        <button className="relative p-2 rounded-lg transition-all text-slate-500 hover:bg-slate-50">
          <Bell size={18} className={unreadApplications > 0 ? "text-indigo-500 animate-pulse" : ""} />
          {unreadApplications > 0 && (
            <span className="absolute top-1.5 right-1.5 w-3.5 h-3.5 bg-red-500 border-2 border-white rounded-full flex items-center justify-center text-[7px] font-black text-white">
              {unreadApplications > 9 ? '9+' : unreadApplications}
            </span>
          )}
        </button>

        <div className="h-6 w-px bg-slate-200"></div>

        <div className="flex items-center gap-2">
          <div className="text-right hidden sm:block">
            <p className="text-xs font-black leading-none text-slate-900">{user.name}</p>
            <p className="text-[9px] font-bold text-slate-400 mt-1 uppercase tracking-tight">{user.role}</p>
          </div>
          <div className="relative shrink-0">
             <img src={user.avatar} alt={user.name} className="w-8 h-8 rounded-lg object-cover ring-2 ring-slate-100" />
          </div>
          <button 
            onClick={onLogout}
            className="ml-1 p-2 text-slate-300 hover:text-red-500 rounded-lg transition-colors"
          >
            <LogOut size={18} />
          </button>
        </div>
      </div>
    </header>
  );
};

export default Header;

