        <div className="max-w-7xl mx-auto flex items-center justify-between">
          <button onClick={() => onNavigate('home')} className="flex items-center gap-3 group">
            <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center p-1.5 shadow-sm group-hover:scale-105 transition-transform overflow-hidden border border-slate-50">
              <img src={systemLogo} alt="Monte Logo" className="w-full h-full object-contain" />
            </div>
            <span className="hidden sm:block font-black text-slate-900 text-sm tracking-tighter italic">MONTE & CHAISA</span>
          </button>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center gap-5">
            {navLinks.map((link) => (
              <button
                key={link.path}
                onClick={() => onNavigate(link.path)}
                className={`text-[11px] font-black uppercase tracking-widest transition-colors ${
                  currentPath === link.path ? 'text-blue-600' : 'text-slate-500 hover:text-blue-500'
                }`}
              >
                {link.name}
              </button>
