           { label: 'Activos', value: staffStats.active, icon: <CheckCircle2 size={16} className="text-emerald-600"/>, bg: 'bg-emerald-50' },
           { label: 'Docs Vencendo', value: staffStats.expiringDocs, icon: <AlertTriangle size={16} className="text-amber-600"/>, bg: 'bg-amber-50' },
         ].map((stat, i) => (
           <div key={i} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center gap-4">
              <div className={`w-10 h-10 ${stat.bg} rounded-xl flex items-center justify-center shadow-inner`}>{stat.icon}</div>
