              </div>
              <h3 className="text-xs font-black text-slate-900 truncate w-full mb-1">{emp.name}</h3>
              <p className="text-[8px] font-black text-indigo-600 uppercase tracking-widest mb-3 bg-indigo-50 px-2 py-0.5 rounded-md inline-block">{emp.role}</p>
              <div className="flex items-center gap-2 text-slate-400 justify-center">
                 <Mail size={12} />
                 <Phone size={12} />
              </div>
