         </div>
         <button onClick={fetchGlobalStats} className="p-1.5 bg-slate-50 text-slate-400 rounded-lg hover:text-indigo-600 transition-all">
            <RefreshCw size={14} className={isSyncing ? 'animate-spin' : ''} />
         </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
         {/* IDENTIDADE CARD - Compact */}
