               </div>
               <input type="text" value={logoUrl} onChange={(e) => setLogoUrl(e.target.value)} className="w-full bg-slate-50 border-none rounded-xl p-3 font-bold text-[9px] outline-none shadow-inner truncate" />
               <button onClick={handleUpdateLogo} disabled={isUpdatingLogo} className="w-full py-3 bg-slate-900 text-white rounded-xl font-black text-[9px] uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-md active:scale-95 disabled:opacity-50">
                  {isUpdatingLogo ? <Loader2 size={14} className="animate-spin" /> : 'Aplicar Marca'}
               </button>
            </div>
         </div>

