                 </AreaChart>
              </ResponsiveContainer>
           </div>
        </div>

        {/* Candidaturas Recentes Column */}
        <div className="xl:col-span-4 space-y-4">
           <div className="bg-white p-5 md:p-6 rounded-2xl border border-slate-100 shadow-sm flex flex-col h-full">
