            </div>
            <button onClick={() => { setEditingEmpId(null); setFormState(initialFormState); setShowAddModal(true); }} className="px-5 py-2 bg-indigo-600 text-white rounded-lg font-black text-[9px] uppercase tracking-widest shadow-md hover:bg-slate-900 transition-all flex items-center gap-2">
               <UserPlus size={14} /> Admitir
            </button>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-3">
            {filteredEmployees.map((emp) => (
              <div key={emp.id} onClick={() => {setViewingEmp(emp); setShowViewModal(true);}} className="bg-white p-4 rounded-xl border border-slate-100 shadow-sm relative group hover:shadow-xl transition-all cursor-pointer overflow-hidden text-center">
                <div className="flex flex-col items-center">
                  <div className="relative mb-3">
                    <img src={emp.avatar} className="w-12 h-12 rounded-lg object-cover ring-2 ring-slate-50 shadow-sm" alt="" />
                    <div className={`absolute -bottom-1 -right-1 w-3 h-3 border-2 border-white rounded-full ${emp.status === 'Ativo' ? 'bg-emerald-500' : 'bg-amber-500'}`}></div>
                  </div>
                  <h3 className="text-[11px] font-black text-slate-900 truncate w-full mb-0.5">{emp.name}</h3>
                  <p className="text-[8px] font-black text-indigo-600 uppercase tracking-widest mb-2 bg-indigo-50 px-1.5 py-0.5 rounded-md inline-block">{emp.role}</p>
                </div>
              </div>
            ))}
          </div>
        </>
      ) : (
        <div className="bg-white rounded-2xl border border-slate-100 shadow-sm overflow-hidden animate-in slide-in-from-right-4 duration-500">
           <div className="p-6 border-b border-slate-50 flex items-center justify-between">
              <h2 className="text-sm font-black text-slate-900 uppercase tracking-widest flex items-center gap-2"><Briefcase size={16} className="text-indigo-600" /> Dossiê de Candidaturas</h2>
              <div className="flex gap-2">
                 <span className="text-[9px] font-black bg-purple-50 text-purple-600 px-3 py-1 rounded-full uppercase">{applications.length} Inscritos</span>
              </div>
           </div>
           <div className="overflow-x-auto">
              <table className="w-full text-left">
                 <thead>
                    <tr className="text-[9px] font-black text-slate-400 uppercase tracking-[0.2em] bg-slate-50/50">
                       <th className="px-6 py-4">Candidato</th>
                       <th className="px-6 py-4">Vaga / Data</th>
                       <th className="px-6 py-4">Perfil / CV</th>
                       <th className="px-6 py-4">Status</th>
                       <th className="px-6 py-4 text-right">Ações</th>
                    </tr>
                 </thead>
                 <tbody className="divide-y divide-slate-50">
                    {applications.map(app => (
                       <tr key={app.id} className="hover:bg-slate-50/30 transition-all group">
                          <td className="px-6 py-5">
                             <p className="text-[11px] font-black text-slate-900 uppercase">{app.applicant_name}</p>
                             <p className="text-[9px] text-slate-400 font-medium">{app.applicant_email}</p>
                          </td>
                          <td className="px-6 py-5">
                             <p className="text-[10px] font-black text-indigo-600 uppercase tracking-tight">{app.job_title}</p>
                             <p className="text-[8px] text-slate-400 uppercase">{new Date(app.created_at).toLocaleDateString('pt-MZ')}</p>
                          </td>
                          <td className="px-6 py-5">
                             {app.applicant_linkedin ? (
                                <a href={app.applicant_linkedin} target="_blank" rel="noopener noreferrer" className="inline-flex items-center gap-2 px-3 py-1.5 bg-blue-50 text-blue-600 rounded-lg text-[9px] font-black uppercase hover:bg-blue-600 hover:text-white transition-all shadow-sm">
                                   <Linkedin size={12} /> Ver Perfil <ExternalLink size={10} />
                                </a>
                             ) : (
                                <span className="text-[8px] font-black text-slate-300 uppercase">Não Fornecido</span>
                             )}
                          </td>
                          <td className="px-6 py-5">
                             <span className={`px-3 py-1 rounded-full text-[8px] font-black uppercase tracking-widest ${app.status === 'Pendente' ? 'bg-amber-50 text-amber-600' : app.status === 'Aprovado' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                                {app.status}
                             </span>
                          </td>
                          <td className="px-6 py-5 text-right">
                             <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => handleUpdateAppStatus(app.id, 'Aprovado')} className="p-2 bg-emerald-50 text-emerald-600 rounded-lg hover:bg-emerald-600 hover:text-white transition-all shadow-sm"><CheckCircle2 size={14}/></button>
                                <button onClick={() => handleUpdateAppStatus(app.id, 'Rejeitado')} className="p-2 bg-rose-50 text-rose-600 rounded-lg hover:bg-rose-600 hover:text-white transition-all shadow-sm"><X size={14}/></button>
                             </div>
                          </td>
                       </tr>
                    ))}
                 </tbody>
              </table>
              {applications.length === 0 && (
                 <div className="py-20 text-center flex flex-col items-center gap-4 opacity-30">
                    <Filter size={32} />
                    <p className="text-[9px] font-black uppercase tracking-widest">Nenhuma candidatura registada na nuvem.</p>
                 </div>
              )}
           </div>
        </div>
      )}
    </div>
  );
};

