                     </div>
                  </div>
               </div>
            </div>
         )}
      </div>

      {/* MODAL: EDITOR DE MATRIZ */}
      {(editingUser || editingRolePermissions) && (
         <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-3xl animate-in fade-in duration-500">
