  const hubItems = [
    { label: 'Fluxo Financeiro', sub: 'Cash Control', val: `${(stats.revenue/1000).toFixed(0)}k`, path: 'finance', icon: <Wallet size={20} />, activeColor: 'bg-emerald-500', glowColor: 'shadow-emerald-500/40' },
